import{t as e}from"./vendor-react-BNgfYwb6.js";import{n as t}from"./vendor-router-_t3d_5JV.js";import{d as n,p as r,t as i}from"./createLucideIcon-CpOOuHCr.js";import"./tag-utils-BcQqUBNA.js";var a=i(`chevron-right`,[[`path`,{d:`m9 18 6-6-6-6`,key:`mthhwq`}]]),o=[{id:`lex-imperfecta`,title:`Lex Imperfecta`,icon:`Scale`,month:`JUN 2026`,story:`The Roman Republic has built a sophisticated legal system to protect its citizens — but the laws were written in haste, and the exceptions were written too generously. Policies go unenforced, the wrong citizens are exempt, and something has slipped through the gates unnoticed. As a newly appointed Praetor, your mission is to restore order before chaos takes hold.`,metaDescription:`The Republic's legal system is in disarray — workloads run unchecked, required labels go missing, and privileged containers slip through the gates. As a...`,tags:[`Kyverno`,`Policy Reporter`,`Kubernetes`],contributor:{name:`Katharina Sick`,url:`https://ksick.dev/`,aboutHtml:`DevRel at Dynatrace and co-organizer of Cloud Native Linz. Passionate about building user-friendly Cloud Native and Kubernetes solutions, with a background in mobile and backend development. Found in tech and sports communities, inline skating rinks, and quiz nights across Europe.`},backstory:[`The Roman Republic has built a sophisticated legal system to protect its citizens — but the laws were written in haste, and the exceptions were written too generously. Policies go unenforced, the wrong citizens are exempt, and something has slipped through the gates unnoticed. As a newly appointed Praetor, your mission is to restore order before chaos takes hold.`],overview:[`The Republic's legal system is in disarray — workloads run unchecked, required labels go missing, and privileged containers slip through the gates. As a newly appointed Praetor, your mission is to restore order by fixing broken Kyverno policies and enforcing proper admission control.`],rewards:{deadline:`2026-06-30T23:59:00+01:00`,eligibility:`Complete all levels and post your solution in the community before the deadline to be eligible.`,tiers:[{label:`1st place`,description:`50% voucher for a Linux Foundation certification`},{label:`Top 3`,description:`Credly badge to showcase the achievement`}],rankingNote:`Ranking is determined by total points across all three levels. Points per level are awarded by submission order within the active week (100 for the first valid solution, 95 for the second, and so on; late submissions still earn 60).`,rankingRulesUrl:`${r}/t/about-the-challenges-category/16`},levels:[{id:`beginner`,name:`The Twelve Tables`,difficulty:`Beginner`,topics:[`Kyverno`,`Kubernetes`],audience:`Platform engineers, SREs, and developers curious about Kubernetes security — no prior Kyverno experience needed, but familiarity with basic <code>kubectl</code> and YAML will help.`,learnings:[`How Kyverno <a href="https://kyverno.io/docs/policy-types/validating-policy/" target="_blank" rel="noopener noreferrer">ValidatingPolicy<span class="sr-only"> (opens in new tab)</span></a> resources and  <a href="https://kubernetes.io/docs/reference/using-api/cel/" target="_blank" rel="noopener noreferrer">CEL validation expressions<span class="sr-only"> (opens in new tab)</span></a> work`,`The difference between <a href="https://kyverno.io/docs/policy-types/validating-policy/" target="_blank" rel="noopener noreferrer">Audit, Deny, and Warn<span class="sr-only"> (opens in new tab)</span></a> validation actions`,`How to use <a href="https://kubernetes.io/docs/concepts/overview/working-with-objects/labels/" target="_blank" rel="noopener noreferrer">custom label keys<span class="sr-only"> (opens in new tab)</span></a> to  enforce workload identity standards`,`How Kyverno <a href="https://kyverno.io/docs/policy-types/mutating-policy/" target="_blank" rel="noopener noreferrer">MutatingPolicy<span class="sr-only"> (opens in new tab)</span></a> resources automatically  patch incoming workloads at admission`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F05-lex-imperfecta_01-beginner%2Fdevcontainer.json&quickstart=1`,discussionUrl:`https://community.offon.dev/t/restore-proper-admission-control-using-kyverno-june-2026-adventure-beginner/1576`,deadline:`2026-06-30T23:59:00+01:00`,intro:[`Fix broken Kyverno policies to restore proper admission control.`],backstory:[`The Republic's legal scholars have been busy — perhaps too busy. In their haste to codify the Twelve Tables, the  foundation of the Republic's legal system, they introduced errors that now threaten the city's order. Workloads  that should be blocked are running freely, and workloads that should be allowed are being turned away at the gates.`,`Another scholar left a note: "I tried to set up policies for privileged containers and required labels, but  something's off — I can't figure out why the wrong things are getting through. There was also supposed to be a  system for automatically issuing travel permits to foreign visitors, but that one is broken too."`,`Your mission: investigate the Kyverno policies and restore proper admission control before chaos reaches the city.`],objective:[`All workloads <strong>missing the <code>republic.rome/gens</code> label</strong> are blocked at admission with a clear policy violation message`,`All workloads <strong>running as privileged containers</strong> are blocked at admission with a clear policy violation message`,`All pods declaring <strong><code>republic.rome/traveler: peregrinus</code></strong> automatically receive the <strong><code>republic.rome/travel-permit: granted</code></strong> label`,`<strong>All other workloads</strong> deploy and run successfully in the cluster`],architecture:[`<p>The Twelve Tables enforced Roman law <strong>at the gates</strong> — before a citizen could act, not after the damage was done. Kyverno works the same way: it intercepts every workload request <em>before</em> it reaches the cluster. A misconfigured policy doesn't just fail to enforce — it fails silently, letting non-compliant workloads slip through while you assume everything is fine.</p>`,`<p>Your Codespace comes with a Kubernetes cluster and Kyverno pre-installed. Three broken policies are already deployed in <code>manifests/policies/</code> — two <code>ValidatingPolicy</code> resources and one <code>MutatingPolicy</code>. Edit them directly and re-apply with <code>kubectl</code>. The pods in <code>manifests/pods/</code> are for reference only — no GitOps, no dashboards.</p>`],architectureDiagram:`/pr-preview/pr-165/assets/lex-imperfecta-beginner-C4vemICb.svg`,diagramAlt:`Workload request flows through Kyverno's admission webhook before reaching the Kubernetes cluster. Two ValidatingPolicy resources block non-compliant workloads, and one MutatingPolicy automatically patches admitted workloads with required labels.`,toolbox:[{name:`kubectl`,description:`Apply and inspect cluster resources`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kyverno CLI`,description:`Test and lint policies locally before applying`,url:`https://kyverno.io/docs/kyverno-cli/`},{name:`k9s`,description:`Explore cluster resources in a terminal UI`,url:`https://k9scli.io/`}],howToPlay:[{title:`Explore the Cluster`,content:`<p>When your Codespace is ready, four pods are already running — or trying to. Open a terminal and check what's going on:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash">kubectl get pods
</code></pre>
<p>Inspect why a pod was blocked or admitted:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash">kubectl describe pod &#x3C;pod-name>
</code></pre>
<p>Check the policies that are in place:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash">kubectl get validatingpolicies
kubectl get validatingpolicy require-labels -o yaml
kubectl get validatingpolicy no-privileged-containers -o yaml

kubectl get mutatingpolicies
kubectl get mutatingpolicy stamp-travel-permit -o yaml
</code></pre>
<p>You can also launch <strong>k9s</strong> for a terminal UI view of all cluster resources:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash">k9s
</code></pre>
<p>Navigate to <code>ValidatingPolicy</code> resources with <code>:validatingpolicies</code> and <code>MutatingPolicy</code> resources with <code>:mutatingpolicies</code> to inspect all three policies.</p>`},{title:`Fix the Policies`,content:`<p>Review the <a href="#objective">Objective</a> and investigate what's wrong in <code>manifests/policies/</code>.</p>
<p>All three broken policies are in <code>manifests/policies/</code>. Read them carefully — each has a different kind of misconfiguration.</p>
<p><strong>Test Locally with the Kyverno CLI</strong></p>
<p>Before applying to the cluster, you can use the <code>kyverno</code> CLI to test your policy changes locally against the workload manifests:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash">kyverno apply manifests/policies/require-labels.yaml --resource manifests/pods/missing-labels.yaml
kyverno apply manifests/policies/no-privileged-containers.yaml --resource manifests/pods/privileged.yaml
kyverno apply manifests/policies/stamp-travel-permit.yaml --resource manifests/pods/peregrinus.yaml
</code></pre>
<p>This gives you fast feedback without touching the cluster.</p>
<p><strong>Apply to the Cluster</strong></p>
<p>Once you're happy with your changes, re-apply everything:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash">make apply
</code></pre>
<p>This re-applies the policies and re-deploys all workloads so you immediately see the effect of your changes.</p>`}],helpfulLinks:[{title:`Kyverno ValidatingPolicy`,url:`https://kyverno.io/docs/policy-types/validating-policy/`,description:`Reference docs for ValidatingPolicy — the resource type you'll fix to block non-compliant workloads`},{title:`Kyverno MutatingPolicy`,url:`https://kyverno.io/docs/policy-types/mutating-policy/`,description:`Reference docs for MutatingPolicy — the resource type you'll fix to auto-stamp travel permits`},{title:`CEL Validation Expressions`,url:`https://kubernetes.io/docs/reference/using-api/cel/`,description:`How CEL expressions work in Kubernetes admission — what you'll write inside the policy rules`},{title:`Kyverno Playground`,url:`https://playground.kyverno.io`,description:`Test your CEL expressions interactively against sample resources before applying them to the cluster`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`},metaDescription:`The Twelve Tables: Fix broken Kyverno policies to restore proper admission control. A beginner Kyverno, Kubernetes challenge on OffOn.`},{id:`intermediate`,name:`Governing the Provinces`,difficulty:`Intermediate`,topics:[`Kyverno`,`Policy Reporter`,`Kubernetes`],audience:`Platform engineers and SREs who have some familiarity with Kyverno, ideally after completing the Beginner level. You should be comfortable reading Kubernetes YAML and basic kubectl commands.`,learnings:[`How to scope policies using <a href="https://kyverno.io/docs/policy-types/validating-policy/" target="_blank" rel="noopener noreferrer">ValidatingPolicy<span class="sr-only"> (opens in new tab)</span></a> (cluster-wide) and <a href="https://kyverno.io/docs/policy-types/validating-policy/#policy-scope" target="_blank" rel="noopener noreferrer">NamespacedValidatingPolicy<span class="sr-only"> (opens in new tab)</span></a> (per-namespace), and when to use each`,`How <a href="https://kubernetes.io/docs/reference/using-api/cel/" target="_blank" rel="noopener noreferrer">CEL expressions<span class="sr-only"> (opens in new tab)</span></a> in <code>ValidatingPolicy</code> and <code>PolicyException</code> express fine-grained admission conditions`,`How to write and scope a <a href="https://kyverno.io/docs/guides/exceptions/" target="_blank" rel="noopener noreferrer">PolicyException<span class="sr-only"> (opens in new tab)</span></a> correctly so only the intended workloads are exempt`,`How to use <a href="https://kyverno.github.io/policy-reporter/" target="_blank" rel="noopener noreferrer">Policy Reporter<span class="sr-only"> (opens in new tab)</span></a> and the <a href="https://openreports.io/" target="_blank" rel="noopener noreferrer">OpenReports<span class="sr-only"> (opens in new tab)</span></a> format to audit and debug a policy estate across multiple namespaces`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F05-lex-imperfecta_02-intermediate%2Fdevcontainer.json&quickstart=1`,discussionUrl:`https://community.offon.dev/t/fix-a-broken-kyverno-policy-estate-june-2026-adventure-intermediate/1581`,deadline:`2026-06-30T23:59:00+01:00`,intro:[`Fix a misconfigured Kyverno policy estate and use Policy Reporter to restore proper governance across the Republic's provinces.`],backstory:[`The Republic has grown. What once was a single city is now a sprawling empire of provinces, each governed by different magistrates with different needs. The legal scholars decided to catalogue every law in a central archive (the Tabularium) so that each province's statutes could be tracked and audited in one place.`,`But cataloguing the laws introduced new chaos. Policies meant for one province are bleeding into another. Exceptions that were meant to be narrow have been written too broadly. And somewhere in the estate, a workload is slipping through that shouldn't be.`,`The Tabularium's auditors have handed you a report: Policy Reporter shows violations where there should be none, and silence where there should be enforcement. Your mission: investigate the policy estate, fix the scoping issues, and restore order before the provinces descend into chaos.`],objective:[`<strong>Empire-wide laws</strong> enforce across every province: no privileged containers, every workload carries a valid <code>republic.rome/gens</code> and <code>republic.rome/province</code> matching its namespace, scoped by namespace label rather than hardcoded names`,`<strong>Aegyptus's scribe law</strong> applies only within Aegyptus, admitting <code>republic.rome/role: scribe</code> workloads exclusively`,`The <strong>legacy exception</strong> is scoped to Aegyptus's grandfathered workload and cannot be claimed by any other province`,`The <strong>Tabularium's ledger</strong> is on file: policy reports exported in OpenReports format as <code>estate-audit.yaml</code>`],architecture:[`<p>Five namespaces span the estate: four <strong>provinces</strong> (<code>gallia</code>, <code>hispania</code>, <code>britannia</code>, <code>aegyptus</code>) with <code>republic.rome/realm: province</code>, and <code>castra</code>, the <strong>infra</strong> namespace, with <code>republic.rome/realm: infra</code>. These labels drive policy scoping; use <code>kubectl get ns --show-labels</code> to inspect them.</p>`,`<p>Two <strong>empire-wide</strong> policies cover all provinces: <code>no-privileged-containers</code> and <code>require-census</code> (every workload must declare a valid <code>republic.rome/gens</code> and a matching <code>republic.rome/province</code>). Aegyptus adds <code>aegyptus-require-scribe-role</code> for its local scribe requirement, and a <strong><code>PolicyException</code></strong> covers its single legacy workload.</p>`,`<p>The broken policies live in <code>manifests/policies/</code> and <code>manifests/exceptions/</code>. After each change, run <code>make apply</code> to redeploy the workloads, then <code>make verify</code> to check your progress.</p>`],toolbox:[{name:`kubectl`,description:`Apply and inspect cluster resources, check namespace labels and policy status`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kyverno CLI`,description:`Test and lint policies locally before applying to the cluster`,url:`https://kyverno.io/docs/kyverno-cli/`},{name:`k9s`,description:`Explore cluster resources and policy reports in a terminal UI`,url:`https://k9scli.io/`}],howToPlay:[{title:`Explore the Estate`,content:`<p>When your Codespace is ready, the policy estate is already deployed, but something is wrong.
Open Policy Reporter at port <strong>30110</strong> (find it in the <strong>Ports</strong> tab) to get an overview of the estate:</p>
<ul>
<li>Which namespaces have violations?</li>
<li>Which policies are generating results, and which are silent when they shouldn't be?</li>
</ul>
<p>Then dig into the cluster:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash"># Inspect the namespace topology — the labels here drive policy scoping
kubectl get ns --show-labels

# List all policies — note which are cluster-wide and which are namespaced
kubectl get validatingpolicies
kubectl get namespacedvalidatingpolicies -A

# Inspect any policy or exception in full
kubectl get validatingpolicy &#x3C;name> -o yaml
kubectl get policyexceptions -A -o yaml

# See the raw OpenReports data behind Policy Reporter
kubectl get policyreports -A
</code></pre>
<p>You can also launch <strong>k9s</strong> for a terminal UI view:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash">k9s
</code></pre>`},{title:`Fix the Policies`,content:`<p>Review the <a href="#objective">Objective</a> and investigate what is wrong in <code>manifests/policies/</code> and
<code>manifests/exceptions/</code>.</p>
<p>Think about what each policy is <em>supposed</em> to cover, and compare that against what it is <em>actually</em>
matching. The namespace labels you saw with <code>kubectl get ns --show-labels</code> are a key part of the picture.</p>
<p><strong>Test locally with the Kyverno CLI before applying:</strong></p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash">kyverno apply manifests/policies/require-census.yaml --resource manifests/workloads/citizens.yaml
kyverno apply manifests/policies/aegyptus-require-scribe-role.yaml --resource manifests/workloads/aegyptus-legacy-scribe.yaml
</code></pre>
<p><strong>Apply your changes to the cluster:</strong></p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash">make apply
</code></pre>
<p>Policies only act at admission, so <code>make apply</code> redeploys the workloads to re-evaluate the estate against
your changes. Then check Policy Reporter again. The picture should improve as you fix each issue.</p>`},{title:`File the Audit`,content:`<p>Once the estate is in order, the Senate expects the Tabularium's ledger on file. Export the cluster's
policy reports, the OpenReports data behind Policy Reporter, as the audit of record.</p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash">kubectl get policyreports -A -o yaml > estate-audit.yaml
</code></pre>`}],helpfulLinks:[{title:`Kyverno ValidatingPolicy`,url:`https://kyverno.io/docs/policy-types/validating-policy/`,description:`Reference docs for ValidatingPolicy and NamespacedValidatingPolicy: the policy types you'll fix`},{title:`Kyverno PolicyException`,url:`https://kyverno.io/docs/guides/exceptions/`,description:`How to write and scope a PolicyException to exempt specific workloads`},{title:`CEL Validation Expressions`,url:`https://kubernetes.io/docs/reference/using-api/cel/`,description:`How CEL expressions work in Kubernetes admission, including accessing namespace context`},{title:`Policy Reporter`,url:`https://kyverno.github.io/policy-reporter/`,description:`How to use Policy Reporter to audit and visualise policy results across the cluster`},{title:`OpenReports Format`,url:`https://openreports.io/`,description:`The OpenReports standard that Kyverno uses to emit PolicyReport resources`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`},metaDescription:`Governing the Provinces: Fix a misconfigured Kyverno policy estate and use Policy Reporter to restore proper governance across the Republic's provinces.`},{id:`expert`,name:`Quis Custodiet`,difficulty:`Expert`,topics:[`Kyverno`,`Policy Reporter`,`Kubernetes`],audience:`Security engineers and platform engineers who want to explore the boundary between admission control and runtime security. Completing the Intermediate level first is helpful but not required. You should be comfortable reading Kyverno ValidatingPolicies and CEL expressions. No prior Falco experience required.`,learnings:[`How <a href="https://falco.org/docs/reference/rules/" target="_blank" rel="noopener noreferrer">Falco rules<span class="sr-only"> (opens in new tab)</span></a> are structured: conditions, output, and kernel-level fields, and how to write a rule targeting a specific runtime behaviour`,`Why <code>privileged: false</code> is not enough: how <a href="https://kubernetes.io/docs/tasks/configure-pod-container/security-context/#set-capabilities-for-a-container" target="_blank" rel="noopener noreferrer">Linux capabilities<span class="sr-only"> (opens in new tab)</span></a> grant host-level access without the privileged flag`,`How to use <a href="https://kyverno.io/docs/policy-types/validating-policy/" target="_blank" rel="noopener noreferrer">spec.variables<span class="sr-only"> (opens in new tab)</span></a> in a <code>ValidatingPolicy</code> to share reusable CEL expressions across validations`,`How pod volumes reference secrets, and why a volume's name and the secret it mounts are two separate fields in the pod spec`,`How <a href="https://github.com/falcosecurity/falcosidekick" target="_blank" rel="noopener noreferrer">Falcosidekick<span class="sr-only"> (opens in new tab)</span></a> aggregates Falco alerts and how to use its UI to watch a runtime incident in real time`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F05-lex-imperfecta_03-expert%2Fdevcontainer.json&quickstart=1`,discussionUrl:`https://community.offon.dev/t/catch-the-intruder-the-guard-couldnt-see-june-2026-adventure-expert/1591`,deadline:`2026-06-30T23:59:00+01:00`,intro:[`An intruder is already inside the Republic, and the watchmen cannot see it. Fix the Praetorian Guard's broken detection rule, close the admission gap that let the intruder slip through, and seal the census archive against unauthorized access.`],backstory:[`The Republic's defences have always rested on the law: block the wrong workloads at the gate, and nothing bad gets in. But the Senate's Praetorian Guard was built for a different threat: the workload that slips through and acts badly at runtime. The Guard watches the provinces through Falco, but tonight, the watchtower is dark. Someone broke the rule that should fire when the census archive is touched. The Guard sees nothing.`,`And while the Guard slept, an intruder crept in. It declared valid labels, passed the census, and presented itself as a loyal citizen of the Republic. Its papers were in order. Its power was not. Once inside, it reached straight for the census archive: the imperial rolls of every citizen, sealed records it had no right to touch. It reads them on a loop and tries to send them out of the Republic.`],objective:[`<strong>The Praetorian Guard awake</strong>: Falco fires an alert every time an unauthorized process reads the census archive, with live alerts streaming into the Falcosidekick UI`,`<strong>The gate closed</strong>: the intruder is denied re-admission. The policy that kept privileged containers out now covers every path to unchecked host power`,`<strong>The archive sealed</strong>: the census-archive secret is inaccessible to any workload that does not bear the Archivist role`,`<strong>The empire-wide laws holding</strong>: all intermediate-level checks still green across every province`],architecture:[`<p>The estate inherits the full intermediate topology: four province namespaces (<code>gallia</code>, <code>hispania</code>, <code>britannia</code>, <code>aegyptus</code>) and one infra namespace (<code>castra</code>), each labelled as before. Alongside the Kyverno stack and Policy Reporter, the cluster now runs <strong>Falco</strong> (eBPF-based, as a DaemonSet) and <strong>Falcosidekick</strong> with its UI at port <strong>30111</strong>. At startup, an intruder pod is already running in one of the provinces, quietly reading the census archive: imperial rolls that only workloads bearing the <code>republic.rome/role: archivist</code> label are permitted to access.</p>`,`<p>Your working directory is the challenge root. <code>manifests/secrets/</code> and <code>manifests/workloads/</code> are already in place. They define the estate and the intruder, and need no changes. Everything else is yours to investigate and fix.</p>`],toolbox:[{name:`kubectl`,description:`Apply and inspect cluster resources, check pod status and security contexts`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`k9s`,description:`Explore cluster resources, pod logs, and policy reports in a terminal UI`,url:`https://k9scli.io/`},{name:`kyverno`,description:`Test a policy against a resource locally before applying it to the cluster`,url:`https://kyverno.io/docs/kyverno-cli/`}],howToPlay:[{title:`Survey the Scene`,content:`<p>When your Codespace opens, the intruder is already running. Open the <strong>Falcosidekick UI</strong> at
the forwarded port <strong>30111</strong>. It should be streaming alerts about census archive reads,
but it is silent. That silence is your first clue that something is wrong with the Guard.</p>
<p>Start by getting oriented:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-bash"># Can you find the intruder?
kubectl get pods -A

# Read the Falco rule that should be firing
cat falco-rules.yaml

# Which policies are in force?
kubectl get validatingpolicies
kubectl get namespacedvalidatingpolicies -A
</code></pre>
<p>Open <strong>Policy Reporter</strong> at port <strong>30110</strong> as well. The intermediate estate should look clean:
the intruder left no trace at admission. That is part of the problem.</p>`},{title:`Act 1: Wake the Praetorian Guard`,content:`<p>The Falco rule in <code>falco-rules.yaml</code> has a defect: find the break, fix it, and run <code>make apply</code>;
alerts streaming into the <strong>Falcosidekick UI at port 30111</strong> are your signal. The
<a href="https://falco.org/docs/reference/rules/supported-fields/" target="_blank" rel="noopener noreferrer">Falco condition fields reference<span class="sr-only"> (opens in new tab)</span></a>
documents every available field.</p>`},{title:`Act 2: Close the Gate`,content:`<p>The intruder passed admission: find the policy gap that let it through, close it, and run
<code>make apply</code>; re-admission denied and the <strong>Falcosidekick UI</strong> going quiet confirm Act 2 is done.
The existing policy already uses <a href="https://kyverno.io/docs/policy-types/validating-policy/" target="_blank" rel="noopener noreferrer">spec.variables<span class="sr-only"> (opens in new tab)</span></a>
to share expressions across validations, a pattern worth exploring.</p>`},{title:`Act 3: Seal the Archive`,content:`<p>Open <code>manifests/policies/</code>: something is missing; the other policies show the structure, write
what's needed, then run <code>make apply</code>.</p>
<p><strong>Going further:</strong> even with the archive sealed at admission, any workload admitted with the
Archivist role can read the secret. Kubernetes RBAC can restrict which service accounts may
<code>get</code> a secret at the API level, a complementary layer that admission control alone cannot
provide.</p>`}],helpfulLinks:[{title:`Falco Rules Reference`,url:`https://falco.org/docs/reference/rules/`,description:`The anatomy of a Falco rule: condition, output, priority, tags, and how rules are evaluated`},{title:`Falco Condition Fields`,url:`https://falco.org/docs/reference/rules/supported-fields/`,description:`Every field available in Falco rule conditions: syscall events, file descriptors, process info, and Kubernetes metadata`},{title:`Linux Capabilities in Kubernetes`,url:`https://kubernetes.io/docs/tasks/configure-pod-container/security-context/#set-capabilities-for-a-container`,description:`How Linux capabilities work and how to configure or restrict them in a pod's security context`},{title:`Kyverno ValidatingPolicy`,url:`https://kyverno.io/docs/policy-types/validating-policy/`,description:`Reference docs for ValidatingPolicy, including spec.variables for composing reusable CEL expressions`},{title:`CEL Validation Expressions`,url:`https://kubernetes.io/docs/reference/using-api/cel/`,description:`How CEL expressions work in Kubernetes admission: operators, optional chaining, and collection functions`},{title:`Falcosidekick`,url:`https://github.com/falcosecurity/falcosidekick`,description:`The Falco alert aggregator that routes Falco events to sinks including the Falcosidekick UI`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`},metaDescription:`Quis Custodiet: An intruder is already inside the Republic, and the watchmen cannot see it. Fix the Praetorian Guard's broken detection rule, close the...`}]},{id:`blind-by-design`,title:`Blind by Design`,icon:`FlaskConical`,month:`MAY 2026`,story:`Three levels of OpenFeature with flagd as the provider, in a Java + Spring Boot service. Wire the SDK against a flagd sidecar (Beginner), layer evaluation context to target by cohort (Intermediate), then instrument flag evaluations with OpenTelemetry and roll back a misbehaving fractional rollout (Expert). All without redeploying.`,metaDescription:`OpenFeature is a vendor-neutral standard for feature flags. The reference cloud-native implementation is flagd, which serves flag definitions from a JSON...`,tags:[`OpenFeature`,`flagd`,`Spring Boot`,`Java`,`OpenTelemetry`,`Grafana`],contributor:{name:`Simon Schrottner`,url:`https://schrottner.at/`,aboutHtml:`CNCF Ambassador and maintainer of OpenFeature and JUnit Pioneer. Helps teams release faster and with more confidence through open standards, feature flagging, and the communities that make both possible. A familiar face at KubeCon EU, Devoxx, ContainerDays, and meetups across Europe.`},backstory:[`The Aletheia Institute is running a multi-phase vision-enhancement trial. The lab is a Spring Boot service whose one job is to record the vision_state of every subject who walks through the protocol (blurry, sharp, enhanced, or clouded), because subjects don't all arrive with the same biology, the same dose adherence, or the same trial-jurisdiction baseline. The flag definitions that drive those readings live in flags.json, watched by a flagd sidecar; the OpenFeature SDK is supposed to call that sidecar on every evaluation.`,`It hasn't been. For the past eight months, every subject through the door has been recorded as "untreated": the integration was never finished, and the lab director assumed the system was reading the chart. Worse, eight weeks ago the Institute opened its flagship Phase 3 trial: a new amplifier variant rolled out fractionally to a cohort by a targeting rule in flags.json. Four adverse-event reports have since been filed, each one a subject whose vision_state at discharge was worse than at enrollment.`,`The monitoring is dark, not by accident, but because no one ever turned the lights on. Your mission across three levels: stand up the lab so it reads the chart, read the chart by cohort so outcomes can be tracked, then turn on the lights and roll back the Phase 3 variant before the director signs off on the next enrollment batch.`],overview:[`OpenFeature is a vendor-neutral standard for feature flags. The reference cloud-native implementation is flagd, which serves flag definitions from a JSON file, locally or remotely, and the OpenFeature SDK in your application calls it on every evaluation.`,`In this adventure, the lab uses OpenFeature exactly the way a real engineering team would: a Spring Boot service holds the SDK client, flagd holds the flag definitions, and the targeting rules in flags.json decide what reading every subject ends up with. By the end, you'll have wired the SDK in from scratch, learned to record outcomes by cohort, and rolled back a misbehaving Phase 3 trial without redeploying.`],rewards:{deadline:`2026-05-26T23:59:00+01:00`,eligibility:`Complete all levels and post your solution in the community before the deadline to be eligible.`,tiers:[{label:`1st place`,description:`50% voucher for a Linux Foundation certification`},{label:`Top 3`,description:`Credly badge to showcase the achievement`}],rankingNote:`Ranking is determined by total points across all three levels. Points per level are awarded by submission order within the active week (100 for the first valid solution, 95 for the second, and so on; late submissions still earn 60).`,rankingRulesUrl:`${r}/t/about-the-challenges-category/16`},levels:[{id:`beginner`,name:`Stand up the Lab`,difficulty:`Beginner`,topics:[`OpenFeature`,`flagd`,`Spring Boot`],audience:`Platform engineers, SREs, and developers curious about feature flags, with no prior OpenFeature experience needed, but familiarity with Spring Boot and basic Java will help.`,learnings:[`How an OpenFeature client and provider work together: the SDK is provider-agnostic and the flagd provider plugs in via dependency only`,`What remote provider means in practice: the SDK calls a separate flag service (flagd) over gRPC, not parsing flags.json itself`,`What flags.json looks like for flagd (state, variants, defaultVariant)`,`Why hot-reload of the flag file matters operationally: configuration without redeploy`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F04-blind-by-design_01-beginner%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/wire-openfeature-flagd-into-a-spring-boot-service-with-zero-setup-adventure-04-beginner/1419`,deadline:`2026-05-26T23:59:00+01:00`,intro:[`Wire the OpenFeature Java SDK and the flagd contrib provider into a Spring Boot service so flag evaluations are resolved by a flagd sidecar against a flags.json file. Author your first flag, then prove that editing flags.json flips the response on the next request: no app restart, no flagd restart, no redeploy.`],backstory:[`The lab is on its first shift and it isn't reading the chart. Every subject who walks through the door gets the same hard-coded reading on their record, no matter what the lab director just signed off on. The label coming out of the lab is a literal string baked into the controller, not a reading pulled from the chart.`,`Your mission: replace that hard-coded label with an OpenFeature client, point that client at the flagd sidecar that already runs next to your Codespace, and let flags.json drive what gets recorded as the subject's vision_state. Prove the lab can change what it records without restarting anything.`],objective:[`curl <a href="http://localhost:8080/" target="_blank" rel="noopener noreferrer">http://localhost:8080/<span class="sr-only"> (opens in new tab)</span></a> returns a vision_state reading resolved from flags.json (not the hard-coded 'untreated' fallback)`,`The response payload includes OpenFeature evaluation details: flag key, variant, reason, and value`,`Editing flags.json to change defaultVariant causes the next request to return the new variant without restarting the app or flagd`],architecture:[`<p>This level runs as two containers side-by-side in your Codespace: the Spring Boot lab and a flagd sidecar.</p>`,`<p>The Spring Boot service runs on <a href="http://localhost:8080/" target="_blank" rel="noopener noreferrer">http://localhost:8080/<span class="sr-only"> (opens in new tab)</span></a> with one endpoint, GET /. flags.json is mounted read-only into the flagd sidecar; edit it through the IDE and flagd's file watcher picks up the change within about a second. The flagd sidecar serves flag evaluations over gRPC on :8013. The OpenFeature SDK reads FLAGD_HOST and FLAGD_PORT from the environment (pre-set by the devcontainer), so there is no host or port to hard-code.</p>`],toolbox:[{name:`./mvnw`,description:`Maven wrapper checked in next to pom.xml, builds and runs the Spring Boot lab`},{name:`curl`,description:`makes requests to <a href="http://localhost:8080/" target="_blank" rel="noopener noreferrer">http://localhost:8080/<span class="sr-only"> (opens in new tab)</span></a> and shows the reading the lab records`,url:`https://curl.se/`},{name:`jq`,description:`pretty-prints and filters the JSON evaluation details returned by the SDK`,url:`https://jqlang.org/`},{name:`flagd sidecar`,description:`already running in the devcontainer compose stack on the docker-internal network, no port forwarding needed`}],howToPlay:[{title:`Start the Lab`,content:`<p>Run the lab from the terminal, or press F5 in VS Code with <code>Laboratory.java</code> open. The lab starts in the broken state, returning the hard-coded 'untreated' response:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">./mvnw spring-boot:run
</code></pre>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 8080:</strong> Spring Boot lab. The lab endpoint. On first load you will see the hard-coded 'untreated' response. This is the broken state you are fixing.</li>
</ul>`},{title:`Add Dependencies`,content:`<p>Add the OpenFeature Java SDK and flagd contrib provider to <code>pom.xml</code>. GroupIds, artifactIds, and versions are in the OpenFeature Java SDK docs and the flagd Java provider README.</p>`},{title:`Configure the Provider`,content:`<p>Create a Spring <code>@Configuration</code> class that builds a <code>FlagdProvider</code> in RPC mode and registers it on the OpenFeature API at startup. No host or port to configure: the devcontainer pre-sets <code>FLAGD_HOST</code> and <code>FLAGD_PORT</code>.</p>`},{title:`Author Your First Flag`,content:`<p>Open <code>flags.json</code> and add a flag named <code>vision_state</code> with two string variants (for example 'blurry' and 'clouded') and a <code>defaultVariant</code>. flagd's file watcher picks up changes within about a second, no restart needed.</p>`},{title:`Wire the Evaluation`,content:`<p>Replace the hard-coded return in <code>Trial</code> with an OpenFeature evaluation of <code>vision_state</code>, returning the full evaluation details (flag key, variant, value, reason).</p>`},{title:`Test Hot Reload`,content:`<p>Restart the lab. Confirm the value resolves from <code>flags.json</code>, then edit <code>flags.json</code>, change <code>defaultVariant</code>, save, and re-run curl without restarting anything:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">curl -s http://localhost:8080/ | jq
</code></pre>`}],helpfulLinks:[{title:`OpenFeature Java SDK`,url:`https://openfeature.dev/docs/reference/technologies/server/java/`},{title:`flagd Java provider`,url:`https://github.com/open-feature/java-sdk-contrib/tree/main/providers/flagd`},{title:`flagd flag definitions`,url:`https://flagd.dev/reference/flag-definitions/`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`},metaDescription:`Wire the OpenFeature Java SDK and flagd provider into a Spring Boot service. Author a flag in flags.json and prove hot-reload works without restarting the app.`},{id:`intermediate`,name:`Outcome by Cohort`,difficulty:`Intermediate`,topics:[`OpenFeature`,`flagd`,`Spring Boot`,`Java`],learnings:[`How OpenFeature's transaction-context propagation works in a thread-per-request server, and why a ThreadLocalTransactionContextPropagator is the right primitive for Servlet-based apps`,`The difference between request-scoped context (the subject's species) and global evaluation context (the trial's country), and when each is the right tool`,`How hooks let you attach cross-cutting behaviour, audit logging today and OpenTelemetry tracing tomorrow, without modifying every flag evaluation call site`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F04-blind-by-design_02-intermediate%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/outcome-by-cohort-adventure-04-intermediate/1485`,deadline:`2026-05-26T23:59:00+01:00`,intro:[`Populate all three OpenFeature evaluation-context layers on a Spring Boot service and register an AuditHook. Transaction context comes from a HandlerInterceptor, global context from the COUNTRY environment variable at startup, and invocation context at the call site. The targeting in flags.json already has three branches for species, dose, and country, but none fire yet because the context layers are missing.`],backstory:[`The trial is widening. Subjects from outside the lab's local population are getting the wrong reading on their chart, and the lab director has just walked in holding a stack of complaint forms. She wants the audit log to tell her, after the fact, exactly which vision_state the lab recorded for which subject, and she wants the lab to read the chart properly before it records any more bad readings.`,`The protocol is the same for every subject; the lab is not varying the trial. What differs is the observed outcome: some subjects have a biology that responds enhancedly to the same serum, some absorb less or more than the protocol's standard dose, and the trial is registered in different jurisdictions with different baselines.`,`Your shift: teach the lab to read each subject's species off the request, attach the trial's country of registration (set on the JVM via the COUNTRY environment variable) to the global context, pass the dose as invocation context at the moment of the flag evaluation, and register an audit hook that records every dose with its variant and reason.`],objective:[`curl /?species=zyklop returns 'enhanced' regardless of dose or country`,`With COUNTRY=de, curl /?dose=standard returns 'sharp'; with COUNTRY=at, the same call falls through to the default`,`curl /?dose=underdose returns 'clouded'; curl /?species=zyklop&#x26;dose=underdose returns 'enhanced' (species takes precedence)`,`Every evaluation produces an [AUDIT] log line naming the flag, the resolved variant, the reason, and the attributes that drove the outcome`,`The response is never 'untreated' (that fallback only fires when the SDK cannot reach flagd)`],architectureDiagram:`/pr-preview/pr-165/assets/blind-by-design-intermediate-DdSTFQMV.svg`,diagramAlt:`HTTP flows through SpeciesInterceptor, Trial, and OpenFeature client left to right, then down through AuditHook and FlagdProvider, connecting via gRPC to a flagd sidecar.`,toolbox:[{name:`Java 21 (Temurin)`,description:`pre-installed in the devcontainer`},{name:`./mvnw`,description:`Spring Boot Maven Wrapper, no global Maven install required`},{name:`curl`,description:`sends requests to <a href="http://localhost:8080/" target="_blank" rel="noopener noreferrer">http://localhost:8080/<span class="sr-only"> (opens in new tab)</span></a> to test each targeting branch`,url:`https://curl.se/`},{name:`jq`,description:`pretty-prints the JSON evaluation details`,url:`https://jqlang.org/`},{name:`tail -f`,description:`watches the application log live for [AUDIT] lines`}],howToPlay:[{title:`Wait for Setup`,content:`<p>Wait ~2-3 minutes for the Java toolchain to install. Use <code>Cmd/Ctrl + Shift + P</code> then <code>View Creation Log</code> to watch progress. When the post-create finishes you'll have Java 21, the Maven wrapper, and the broken-state lab ready in <code>adventures/04-blind-by-design/intermediate/</code>.</p>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 8080:</strong> Spring Boot lab. The application under test. Access via the Ports tab or curl <a href="http://localhost:8080/" target="_blank" rel="noopener noreferrer">http://localhost:8080/<span class="sr-only"> (opens in new tab)</span></a>.</li>
</ul>`},{title:`Confirm the Broken State`,content:`<p>Start the lab and confirm the broken state, where no targeting fires yet:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">./mvnw spring-boot:run
curl 'http://localhost:8080/?species=zyklop'
# returns 'blurry', wrong cohort, targeting can't fire
</code></pre>
<p>That <code>"blurry"</code> is the starting point you want: even when the request shouts <code>species=zyklop</code>, the lab has nothing in its evaluation context, so flagd's targeting cannot fire and every subject drops to the default variant. Stop the app and start fixing.</p>`},{title:`Inspect the Starting Point`,content:`<p>The lab already has the OpenFeature SDK and the flagd contrib provider on the classpath, and the <code>FlagdProvider</code> is wired in <code>Resolver.RPC</code> mode against the flagd sidecar. Open <code>flags.json</code> and inspect the targeting. Three branches exist but none fire because nothing in the app populates <code>species</code>, <code>country</code>, or <code>dose</code> yet:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-json">"targeting": {
  "if": [
    { "===": [{"var": "species"}, "zyklop"] },        "enhanced",
    { "in":  [{"var": "dose"}, ["underdose", "overdose"]] }, "clouded",
    { "===": [{"var": "country"}, "de"] },             "sharp"
  ]
}
</code></pre>
<p>Your job: populate <code>species</code>, <code>country</code>, and <code>dose</code> on the evaluation context so the targeting fires.</p>`},{title:`Build the SpeciesInterceptor`,content:`<p>Create a Spring <code>HandlerInterceptor</code> named <code>SpeciesInterceptor</code>: in <code>preHandle</code>, read <code>?species=</code> and put it on the transaction context; in <code>afterCompletion</code>, clear the context so values do not leak across pooled threads. Register a <code>ThreadLocalTransactionContextPropagator</code> once on the OpenFeature API in a static initializer. Without the propagator the SDK has no way to carry per-request context across the call into the controller, and the transaction context silently stays empty.</p>`},{title:`Wire OpenFeatureConfig`,content:`<p>Update <code>OpenFeatureConfig</code> to: register <code>SpeciesInterceptor</code> with Spring (<code>WebMvcConfigurer.addInterceptors</code>), read the <code>COUNTRY</code> environment variable and set it as the global evaluation context, and register <code>AuditHook</code> globally on the OpenFeature API. The three context layers, global (<code>country</code>), transaction (<code>species</code> from the interceptor), and invocation (<code>dose</code> from <code>Trial</code>), merge before flagd evaluates the rules. Precedence on conflict is invocation over transaction over global.</p>`},{title:`Update the Trial`,content:`<p>Update <code>Trial</code> so each evaluation passes <code>dose</code> on the invocation context (the third argument to <code>client.getStringDetails</code>). Default to <code>'standard'</code> most of the time but occasionally to <code>'underdose'</code> or <code>'overdose'</code>, that is the lab tech mis-measuring, and it is what makes the improper-dosing branch in <code>flags.json</code> fire at all. Make it overridable via <code>?dose=</code> so you can test each branch by hand. If the invocation context does not carry <code>dose</code>, the targeting rule sees <code>null</code> and the branch never fires: every non-zyklop request lands on either the country branch or the default.</p>`},{title:`Implement AuditHook`,content:`<p>Implement <code>AuditHook</code>: in <code>after()</code>, write an <code>[AUDIT]</code> log line with flag name, variant, reason, and a fixed allowlist of attributes (species, country, dose). Log at WARN when the variant is <code>'clouded'</code> so the safety officer can grep for it, otherwise INFO. Implement <code>error()</code> so failed evaluations are not silent. Use a fixed allowlist (<code>List.of("species", "country", "dose")</code>) rather than iterating the whole context: audit logs outlive app logs, and logging only what you decided to log pays off the moment something sensitive lands on the context.</p>`},{title:`Test All Targeting Branches`,content:`<p>Run the lab with country-specific scripts. These pipe output through <code>tee app.log</code>, which the verifier greps for <code>[AUDIT]</code> lines. If you run <code>./mvnw spring-boot:run</code> directly, add <code>| tee app.log</code> or the verifier has nothing to grep:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">./run-germany.sh    # COUNTRY=de  (or: make lab-germany)
./run-austria.sh    # COUNTRY=at
</code></pre>
<p>Three named launch configs in <code>.vscode/launch.json</code> (Germany / Austria / No country) also let you switch cohorts from the Run and Debug view.</p>
<p>In another terminal, verify each branch:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">curl -s 'http://localhost:8080/?species=zyklop' | jq .value
# => "enhanced"

curl -s 'http://localhost:8080/?dose=standard' | jq .value
# => "sharp" (Germany) / "blurry" (Austria)

curl -s 'http://localhost:8080/?dose=underdose' | jq .value
# => "clouded"

curl -s 'http://localhost:8080/?species=zyklop&#x26;dose=underdose' | jq .value
# => "enhanced" (species wins)
</code></pre>
<p>Check the audit trail:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">grep '\\[AUDIT\\]' app.log | head
</code></pre>
<p>You should see one <code>[AUDIT] flag=vision_state variant=... reason=... species=... country=... dose=...</code> line per request. <code>clouded</code> outcomes log at WARN.</p>`}],helpfulLinks:[{title:`OpenFeature Java SDK`,url:`https://openfeature.dev/docs/reference/technologies/server/java/`},{title:`OpenFeature Hooks`,url:`https://openfeature.dev/docs/reference/concepts/hooks`},{title:`Spring HandlerInterceptor`,url:`https://docs.spring.io/spring-framework/docs/current/javadoc-api/org/springframework/web/servlet/HandlerInterceptor.html`},{title:`flagd flag definitions`,url:`https://flagd.dev/reference/flag-definitions/`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`},metaDescription:`Add OpenFeature evaluation context and an AuditHook to a Spring Boot service. Target flag evaluations by species, country, and dose to record cohort outcomes.`},{id:`expert`,name:`Read the Chart`,difficulty:`Expert`,topics:[`OpenFeature`,`OpenTelemetry`,`Grafana`,`Spring Boot`],audience:`Platform engineers, SREs, and observability-focused developers who have completed the Beginner and Intermediate levels or are comfortable with OpenFeature evaluation context, and want to learn how flag evaluations join distributed traces and metrics, and how to use a flag flip as an operational lever for live rollbacks.`,learnings:[`How the OpenFeature OpenTelemetry hooks (TracesHook and MetricsHook) join flag evaluations to the rest of an application's telemetry without a separate ingestion path`,`How to author your own Hook: a tiny class that copies merged-eval-context attributes onto the active OTel span, closing the loop between why a flag resolved the way it did and what the operator sees in Tempo`,`How fractional rollout in flagd buckets users by targetingKey (same key, same bucket, every request) and how to read that bucketing off a dashboard`,`How a flag flip is a faster operational lever than a redeploy when a rollout is misbehaving: the difference between a one-line config change and a twenty-minute deployment`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F04-blind-by-design_03-expert%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/read-the-chart-adventure-04-expert/1530`,deadline:`2026-05-26T23:59:00+01:00`,intro:[`Spans are already flowing into Tempo from the OpenFeature TracesHook, but the metrics half is dead: the MeterProvider has no exporter and the MetricsHook was never registered.`,`The dashboard the operator wants to triage from is empty. The k6 loadgen is idle, waiting for a flag flip to turn it on.`],backstory:[`The trial just went wide. Phase 3 of the new vision amplifier (vision_amplifier_v2) was approved for the full cohort yesterday morning. The promise was straightforward: subjects emerge with sharper eyesight than they walked in with. By mid-afternoon the audit log was screaming. Subjects were stabilising 200ms slower, and roughly one in ten of them was emerging blind, with containment failure recorded as an HTTP 500. The lab director pulled up the Feature Flag Metrics dashboard expecting to triage visually. The dashboard was dark. Someone had wired up traces but never finished the metrics half. There is no chart to read. The lab is studying eyesight and the lab itself cannot see.`,`Your job, in order: turn on the lights, find the bad arm of the trial, and halt enrolment on the amplifier, all without redeploying the lab. That last constraint is the whole point of feature flags: when a rollout starts misbehaving in production, you need an operational lever that does not take twenty minutes to pull. Save the file, watch the dose drop, watch the 5xx rate fall back to baseline, watch the next batch of subjects walk out seeing.`],objective:[`Spans for fun-with-flags-java-spring are visible in Tempo with feature_flag.context. attributes. Searching feature_flag.context.dose=underdose lights up requests where a subject was mis-dosed, with feature_flag.variant=clouded on the same span`,`feature_flag_evaluation_requests_total is non-zero in Prometheus: flag evaluations show up as counters, not just spans`,`The Feature Flag Metrics dashboard renders: variant distribution, error rate, and latency p99 are all populated from the metric counters`,`The vision_amplifier_v2 rollout is rolled back to 100% off without redeploying the lab`,`HTTP 5xx rate over the last minute drops below 1%: the bad arm is contained`],architectureDiagram:`/pr-preview/pr-165/assets/blind-by-design-expert-D5RxcQxi.svg`,diagramAlt:`Architecture diagram showing four services: Spring Boot app sends traces via OTLP/gRPC to a Grafana LGTM stack, connects via OpenFeature SDK to flagd for feature flag evaluation, and a k6 load generator polls flagd and scrapes metrics from the LGTM stack.`,toolbox:[{name:`Java 21 (Temurin)`,description:`pre-installed in the devcontainer`,url:`https://adoptium.net/`},{name:`./mvnw`,description:`Spring Boot Maven Wrapper, no global Maven install required`},{name:`curl`,description:`sends requests to <a href="http://localhost:8080/" target="_blank" rel="noopener noreferrer">http://localhost:8080/<span class="sr-only"> (opens in new tab)</span></a> to test the lab, and to Prometheus on <a href="http://localhost:9090/" target="_blank" rel="noopener noreferrer">http://localhost:9090/<span class="sr-only"> (opens in new tab)</span></a> to query metrics directly`,url:`https://curl.se/`},{name:`Grafana`,description:`browser UI at <a href="http://localhost:3000" target="_blank" rel="noopener noreferrer">http://localhost:3000<span class="sr-only"> (opens in new tab)</span></a> (admin/admin) for the Feature Flag Metrics dashboard and Tempo trace explorer`},{name:`jq`,description:`pretty-prints the JSON evaluation details`,url:`https://jqlang.org/`}],howToPlay:[{title:`Start Your Challenge`,content:`<p>The sibling containers (flagd, Grafana LGTM, k6 loadgen) start automatically as part of the devcontainer compose. Wait ~2-3 minutes for them to be ready before moving on.</p>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 8080:</strong> Spring Boot lab. Add ?userId=subject-42 for a stable fractional-rollout bucketing key.</li>
<li><strong>Port 3000:</strong> Grafana (admin / admin). Open Dashboards > Feature Flag Metrics (empty until metrics are wired). Try Explore > Tempo to see flag evaluations as span events.</li>
<li><strong>Port 9090:</strong> Prometheus. Query metrics directly via the Prometheus UI or curl <a href="http://localhost:9090/api/v1/query" target="_blank" rel="noopener noreferrer">http://localhost:9090/api/v1/query<span class="sr-only"> (opens in new tab)</span></a>.</li>
<li><strong>Port 3200:</strong> Tempo. Tempo HTTP API used by the verify script to assert traces are flowing.</li>
</ul>
<p>flagd runs on the docker-internal network only. No port forwarding needed.</p>`},{title:`Start the Lab`,content:`<p>The sibling containers are already up. Boot the Spring Boot lab by clicking <strong>Run</strong> on <code>Laboratory</code> in the Spring Boot Dashboard panel (or press <strong>F5</strong> with <code>Laboratory.java</code> open), or from the terminal:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">./mvnw spring-boot:run
</code></pre>
<p>Spans start flowing into Tempo on the first request. The trace pipeline is already wired. The metrics pipeline is dead (task 4a), so the Grafana dashboard panels stay empty until you fix it.</p>`},{title:`Turn On the Metrics Exporter`,content:`<p>OTel ships two parallel pipelines: traces (already flowing into Tempo) and metrics (dead). The OTel Java Agent attached to the lab JVM has both pipelines plumbed and pointed at the LGTM stack, but <code>otel.properties</code> (next to <code>pom.xml</code>) sets <code>otel.metrics.exporter=none</code>, so anything the meter records goes nowhere.</p>
<p>Open <code>otel.properties</code> and flip the exporter on. While you're there, look at the export interval. The default makes the next steps harder than they need to be.</p>
<p>Once the exporter is on, <code>MetricsHook</code> (next step) finds the working meter provider through <code>GlobalOpenTelemetry</code> without any further plumbing. You will need to restart the lab to pick up the change.</p>`},{title:`Register MetricsHook`,content:`<p><code>OpenFeatureConfig.java</code> registers <code>TracesHook</code> but stops there. <code>MetricsHook</code> needs an <code>OpenTelemetry</code> handle to find the meter provider. The agent installs one globally at JVM start, so <code>GlobalOpenTelemetry.get()</code> is the way to reach it.</p>
<p>Register <code>MetricsHook</code> alongside <code>TracesHook</code> in <code>OpenFeatureConfig</code>. The Feature Flag Metrics dashboard stays empty until traffic drives through. That is what the loadgen step does.</p>`},{title:`Write and Register ContextSpanHook`,content:`<p>The two contrib hooks tell you <em>what</em> happened: which flag, which variant, which reason. What is missing is the <em>why</em> visible in Tempo. Write a <code>ContextSpanHook</code> that copies the merged eval context attributes onto the active OTel span as <code>feature_flag.context.&#x3C;key></code>:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-text">before(hookCtx) {
    span = active OTel span
    for each allowlisted key in merged eval context:
        span.setAttribute("feature_flag.context." + key, value)
}
</code></pre>
<p><code>HookContext.getCtx()</code> returns the merged evaluation context (global + transaction + invocation). Use a fixed allowlist of <code>List.of("species", "country", "dose")</code>. Never iterate the whole context: <code>targetingKey</code> joins to PII in real apps, and span attributes are retained for days in Tempo at scale.</p>
<p>Register <code>ContextSpanHook</code> alongside <code>TracesHook</code> and <code>MetricsHook</code> in <code>OpenFeatureConfig</code>. The verifier searches Tempo for <code>feature_flag.context.dose=underdose</code> once you are done.</p>`},{title:`Turn On the Loadgen`,content:`<p><code>flags.json</code> has two flags: <code>loadgen_active</code> (off by default) and the misbehaving <code>vision_amplifier_v2</code>. flagd watches the file and picks up changes within about a second.</p>
<p>Flip <code>loadgen_active</code> to on. The k6 loadgen polls it every two seconds and starts five virtual users hammering the lab. Within a minute, latency p99 should climb ~200ms and the 5xx rate ~10% on the dashboard, confirming that the bad arm of <code>vision_amplifier_v2</code> is active.</p>`},{title:`Roll Back the Rollout`,content:`<p>The dashboard's variant-distribution panel shows which variant is the culprit. Roll it back by editing <code>flags.json</code> to set <code>vision_amplifier_v2</code> to 100% off.</p>
<p><strong>No deploy. No rebuild. No restart of the lab.</strong></p>
<p>Watch the dashboard: the 5xx rate falls back to baseline, and the next batch of subjects walks out seeing.</p>`}],helpfulLinks:[{title:`OpenFeature OTel contrib hooks (Java)`,url:`https://github.com/open-feature/java-sdk-contrib/tree/main/hooks/open-telemetry`},{title:`OpenTelemetry Java Agent configuration`,url:`https://opentelemetry.io/docs/zero-code/java/agent/configuration/`},{title:`OpenFeature Hooks concept`,url:`https://openfeature.dev/docs/reference/concepts/hooks`},{title:`flagd fractional operation`,url:`https://flagd.dev/reference/custom-operations/fractional-operation/`},{title:`OpenTelemetry security guidance`,url:`https://opentelemetry.io/docs/security/`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`},metaDescription:`Wire OpenTelemetry metrics into an OpenFeature Java app, author a ContextSpanHook, then roll back a bad rollout by flipping a flag in flags.json. No redeploy.`}]},{id:`the-ai-observatory`,title:`The AI Observatory`,icon:`Telescope`,month:`FEB 2026`,story:`Investigate a mysterious bandwidth anomaly at a remote research station by instrumenting its AI system with OpenTelemetry, OpenLLMetry, and Jaeger.`,metaDescription:`The AI Observatory: a hands-on OpenTelemetry, OpenLLMetry, Jaeger adventure on OffOn.`,tags:[`OpenTelemetry`,`OpenLLMetry`,`Jaeger`,`Prometheus`,`Python`],contributor:{name:`Katharina Sick`,url:`https://ksick.dev/`,aboutHtml:`DevRel at Dynatrace and co-organizer of Cloud Native Linz. Passionate about building user-friendly Cloud Native and Kubernetes solutions, with a background in mobile and backend development. Found in tech and sports communities, inline skating rinks, and quiz nights across Europe.`},backstory:[`You are stationed at Perimeter Alpha, a research outpost on the newly discovered planet HB-7742. The station is run by HubSystem, a central AI that manages everything from life support to data analysis.`,`Recently, the station's bandwidth usage has spiked to 847% above baseline, but no one knows why. As the systems engineer, it's your job to instrument the AI, trace its activities, and uncover the root cause of the anomaly.`,`Your mission: bring visibility to the station's AI and solve the mystery.`],levels:[{id:`beginner`,name:`Calibrating the Lens`,difficulty:`Beginner`,topics:[`OpenTelemetry`,`OpenLLMetry`,`Jaeger`],learnings:[`Instrument Python AI apps with OpenLLMetry`,`Analyze traces in Jaeger`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F03-the-ai-observatory_01-beginner%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/instrument-your-first-llm-adventure-03-beginner-is-live/865/8`,deadline:`2026-03-08T23:59:00+01:00`,intro:[`Something is eating 847% of your station's bandwidth and nobody knows what. Instrument HubSystem with OpenLLMetry, send traces to the OpenTelemetry Collector, and use Jaeger to uncover what the AI is doing behind the scenes.`],backstory:[`You're a researcher stationed at Perimeter Alpha, a remote research outpost on the newly discovered planet HB-7742. Your team of six scientists is protected by a single SecUnit, assigned by the corporation to ensure your safety during the survey mission. All station queries flow through HubSystem, the central AI that manages everything from data analysis to status reports.`,`Three weeks in, you notice something odd in your morning diagnostics: communication module usage at 847% above baseline. Nobody's streaming. Nobody's running large data transfers. The planet surveys are on schedule. So what's consuming all that bandwidth?`,`As the station's systems engineer, you decide to investigate. Time to instrument HubSystem with OpenTelemetry and find out what's really going on.`,`Credits: The characters of this adventure are borrowed from the Murderbot Diaries series by Martha Wells, a brilliant series that is funny, action-packed, and surprisingly heartwarming. It follows a security unit that hacked its own governor module and now just wants to be left alone to watch media, but keeps getting pulled into human nonsense.`],objective:[`Enable OpenTelemetry instrumentation for HubSystem using OpenLLMetry`,`Send traces to the OpenTelemetry Collector at <a href="http://localhost:30107" target="_blank" rel="noopener noreferrer">http://localhost:30107<span class="sr-only"> (opens in new tab)</span></a>`,`Analyze traces in Jaeger to find what causes the high bandwidth usage`,`Provide the correct answer in quiz.txt`],architecture:[`<p>All AI and observability infrastructure (Ollama, OpenTelemetry Collector, Jaeger) runs inside Kubernetes, while HubSystem runs as a local Python application outside the cluster.</p>`,`<p>This setup has two benefits: it lets you focus on instrumentation without wrestling with containers or Kubernetes deployments when updating the app, and it gives you fast iteration. Edit the Python code, run it, and see traces in Jaeger immediately. No build or deploy cycle.</p>`],toolbox:[{name:`python`,description:`programming language used for the HubSystem application`},{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`}],howToPlay:[{title:`Wait for Infrastructure`,content:`<p>Wait ~10 minutes for all infrastructure to initialize.</p>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 30103:</strong> Jaeger. Analyze the traces sent by HubSystem.</li>
</ul>`},{title:`Instrument the App`,content:`<p>The application code is in <code>./hubsystem.py</code>. Add OpenTelemetry instrumentation using OpenLLMetry. The OTel
Collector and Jaeger are already configured correctly; you only need to instrument the app. You do not need to
interact with Kubernetes directly. The cluster is already running, so focus on the Python code.</p>`},{title:`Run and Investigate`,content:`<p>Run the application, interact with the AI to generate traces, then check Jaeger:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">make hubsystem
</code></pre>`},{title:`Answer the Quiz`,content:`<p>Find the trace responsible for the high bandwidth usage and inspect its attributes to answer <code>quiz.txt</code>.</p>`}],helpfulLinks:[{title:`OpenLLMetry SDK for Python`,url:`https://traceloop.com/docs/openllmetry/getting-started-python`},{title:`Jaeger documentation`,url:`https://www.jaegertracing.io/docs/latest/`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`},metaDescription:`Calibrating the Lens: Something is eating 847% of your station's bandwidth and nobody knows what. Instrument HubSystem with OpenLLMetry, send traces to the...`},{id:`intermediate`,name:`The Distracted Pilot`,difficulty:`Intermediate`,topics:[`OpenTelemetry`,`OpenLLMetry`,`Jaeger`,`Prometheus`],learnings:[`Instrument RAG pipelines with OpenLLMetry`,`Create custom OpenTelemetry metrics in Python`,`Write PromQL queries &#x26; recording rules in Prometheus`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F03-the-ai-observatory_02-intermediate%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/instrument-debug-a-rag-pipeline-adventure-03-intermediate-is-live/936/2`,deadline:`2026-03-08T23:59:00+01:00`,intro:[`ART's RAG pipeline is retrieving entertainment data instead of navigation coordinates and won't calculate your jump. Instrument the full retrieval pipeline with OpenLLMetry, build a custom OTel metric to quantify the distraction, and write a Prometheus recording rule to prove it.`],backstory:[`You're a rogue SecUnit who just escaped from Preservation Station after being identified. A researcher helped you flee aboard the Perihelion, a university research vessel with a very opinionated AI.`,`The ship's AI agreed to help you disappear. You've nicknamed it ART. The plan: jump to RaviHyral, lay low, and figure out your next move. Except ART was supposed to have the jump coordinates ready an hour ago.`,`<p>You ping the ship's AI through your internal comm.</p>
<p>SecUnit: "ART. Jump coordinates. Now."</p>
<p>ART: "I'm multitasking. The coordinates are... being compiled."</p>
<p>That's not normal. ART is never vague. You access the ship's diagnostic systems (something you're not supposed to be able to do, but ART hasn't locked you out yet).</p>`,`Your mission: diagnose ART's distraction using OpenTelemetry and fix the navigation system before you miss your jump.`,`Credits: The characters of this adventure are borrowed from the Murderbot Diaries series by Martha Wells, a brilliant series that is funny, action-packed, and surprisingly heartwarming. It follows a security unit that hacked its own governor module and now just wants to be left alone to watch media, but keeps getting pulled into human nonsense.`],objective:[`Instrument the full RAG pipeline with OpenLLMetry (add a span named rag.context_assembly with attribute context.categories)`,`Implement a custom metric art.rag.retrieval.count to track how often ART retrieves entertainment vs navigation data`,`Create a Prometheus recording rule to calculate ART's Distraction Ratio`,`Restore the navigation system so ART successfully calculates jump coordinates to RaviHyral`],architecture:[`<p>The ART Pilot System runs as a local Python application outside Kubernetes, using a RAG (Retrieval-Augmented Generation) architecture. AI infrastructure (Ollama for LLM, Qdrant for vector storage) and observability tools (OpenTelemetry Collector, Jaeger, Prometheus) run inside Kubernetes.</p>`,`<p>This setup lets you focus on observability patterns: edit Python code, run it, and see traces and metrics immediately without a build or deploy cycle.</p>`],toolbox:[{name:`python`,description:`programming language used for the ART application`},{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`}],howToPlay:[{title:`Wait for Infrastructure`,content:`<p>Wait ~15 minutes for all infrastructure to initialize.</p>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 30102:</strong> Prometheus. Explore available metrics and test PromQL queries.</li>
<li><strong>Port 30103:</strong> Jaeger. Shows distributed traces from ART to verify that tracing is working end-to-end.</li>
</ul>`},{title:`Instrument and Configure`,content:`<p>The application code is in <code>./art.py</code>. Instrument it with OpenLLMetry and add the custom metric. The Prometheus recording rules are in <code>./manifests/prometheus-rule.yaml</code>. After changing the rule file, apply it to the cluster:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">make apply
</code></pre>`},{title:`Generate Traffic`,content:`<p>Run the application to interact with ART ("Calculate jump"), or generate continuous traffic for your metric graphs:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">make art
# or for continuous traffic:
make traffic
</code></pre>`},{title:`Fix the Navigation`,content:`<p>Verify traces in Jaeger and the recording rule in Prometheus. Fix the navigation system so ART returns jump coordinates to RaviHyral.</p>`}],helpfulLinks:[{title:`OpenLLMetry SDK for Python`,url:`https://traceloop.com/docs/openllmetry/getting-started-python`},{title:`OpenTelemetry Python metrics`,url:`https://opentelemetry.io/docs/languages/python/instrumentation/#metrics`},{title:`Prometheus recording rules`,url:`https://prometheus.io/docs/prometheus/latest/configuration/recording_rules/`},{title:`Qdrant filtering`,url:`https://qdrant.tech/documentation/concepts/filtering/`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`},metaDescription:`The Distracted Pilot: ART's RAG pipeline is retrieving entertainment data instead of navigation coordinates and won't calculate your jump. Instrument the...`},{id:`expert`,name:`The Noise Filter`,difficulty:`Expert`,topics:[`OpenTelemetry`,`OpenLLMetry`,`Jaeger`],learnings:[`OpenTelemetry GenAI semantic conventions`,`Tail sampling in the OTel Collector`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F03-the-ai-observatory_03-expert%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/reduce-telemetry-noise-adventure-03-expert-is-live/999/1`,deadline:`2026-03-08T23:59:00+01:00`,intro:[`ART is flooding Jaeger with 40,000 non-standard spans an hour. Fix the chat span to follow OpenTelemetry GenAI semantic conventions with proper token usage attributes, then configure tail sampling in the Collector to keep only traces that contain errors or exceed 5 seconds.`],backstory:[`You made it to RaviHyral. The Perihelion docked at Outpost Verada, a small independent research station run by a loose collective of academics who agreed to look the other way. In exchange, ART offered to share its observability data with the station's monitoring team.`,`<p>That was three hours ago. Now the station's lead engineer is at your docking port, looking annoyed.</p>
<p>Engineer: "Your ship's AI is flooding our Jaeger instance. Do you have any idea how many spans it's generating? We can't find anything in there."</p>
<p>SecUnit: "ART."</p>
<p>ART: "Comprehensive telemetry is a feature."</p>
<p>Engineer: "It's 40,000 spans an hour. Every healthy query. Every token. It doesn't even follow conventions. We only care about failures and anomalies, the things that actually need attention."</p>
<p>SecUnit: "ART. Fix it."</p>
<p>ART: "...Fine."</p>`,`The engineer hands you access to the collector config and the application code, then walks away. Two problems to fix. ART's spans don't follow OTel GenAI semantic conventions, and the collector is forwarding everything.`,`Credits: The characters of this adventure are borrowed from the Murderbot Diaries series by Martha Wells, a brilliant series that is funny, action-packed, and surprisingly heartwarming. It follows a security unit that hacked its own governor module and now just wants to be left alone to watch media, but keeps getting pulled into human nonsense.`],objective:[`Fix ART's chat span to follow OpenTelemetry GenAI semantic conventions, including token usage attributes`,`Configure tail sampling in the OpenTelemetry Collector to keep only traces that contain errors or take longer than 5 seconds`],architecture:[`<p>Same setup as the intermediate level: the ART Pilot System runs as a local Python application outside Kubernetes with a RAG architecture. AI infrastructure (Ollama, Qdrant) and observability tools (OpenTelemetry Collector, Jaeger) run inside Kubernetes.</p>`],toolbox:[{name:`python`,description:`programming language used for the ART application`},{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`}],howToPlay:[{title:`Wait for Infrastructure`,content:`<p>Wait ~15 minutes for all infrastructure to initialize.</p>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 30103:</strong> Jaeger. Verify your spans look correct and that tail sampling works as expected.</li>
</ul>`},{title:`Fix Instrumentation and Sampling`,content:`<p>Fix two things:</p>
<ol>
<li>The application code in <code>./art.py</code>: update the <code>chat</code> span to follow OpenTelemetry GenAI semantic conventions, including token usage attributes.</li>
<li>The collector config in <code>./manifests/otel-collector-config.yaml</code>: configure tail sampling to keep only traces that contain errors or take longer than 5 seconds.</li>
</ol>`},{title:`Apply and Test`,content:`<p>After changing <code>art.py</code>, restart traffic to pick up new instrumentation. After changing the collector config, apply it:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">kubectl apply -f manifests/otel-collector-config.yaml -n otel
kubectl rollout restart deployment/collector -n otel
</code></pre>
<p>Then generate traces:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">make traffic
</code></pre>
<p>Verify in Jaeger that spans follow conventions and only errors and slow traces appear.</p>`}],helpfulLinks:[{title:`OpenTelemetry GenAI semantic conventions`,url:`https://opentelemetry.io/docs/specs/semconv/gen-ai/gen-ai-spans/`},{title:`OpenTelemetry Python: recording exceptions`,url:`https://opentelemetry.io/docs/languages/python/instrumentation/#record-exceptions`},{title:`OTel Collector tail sampling processor`,url:`https://github.com/open-telemetry/opentelemetry-collector-contrib/tree/main/processor/tailsamplingprocessor`},{title:`Python contextlib.contextmanager`,url:`https://docs.python.org/3/library/contextlib.html#contextlib.contextmanager`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`},metaDescription:`The Noise Filter: ART is flooding Jaeger with 40,000 non-standard spans an hour. Fix the chat span to follow OpenTelemetry GenAI semantic conventions with...`}]},{id:`building-cloudhaven`,title:`Building CloudHaven`,icon:`Cloud`,month:`JAN 2026`,story:`Join the Infrastructure Guild and modernize CloudHaven's infrastructure from manual provisioning to a self-service platform using Infrastructure as Code. A hands-on journey through infrastructure as code with OpenTofu and GitHub Actions.`,metaDescription:`Building CloudHaven: a hands-on OpenTofu, Terraform, GitHub Actions adventure on OffOn.`,tags:[`OpenTofu`,`Terraform`,`GitHub Actions`,`Trivy`,`TDD`],contributor:{name:`Katharina Sick`,url:`https://ksick.dev/`,aboutHtml:`DevRel at Dynatrace and co-organizer of Cloud Native Linz. Passionate about building user-friendly Cloud Native and Kubernetes solutions, with a background in mobile and backend development. Found in tech and sports communities, inline skating rinks, and quiz nights across Europe.`},backstory:[`Welcome to CloudHaven, a bustling digital metropolis where every district depends on essential services to thrive. You've just joined the Infrastructure Guild, a team of platform engineers responsible for providing the tools and services that keep the city running.`,`CloudHaven is expanding rapidly. The Merchant's Quarter needs storage vaults for their goods and ledgers for tracking inventory. The Scholar's District requires secure archives for ancient texts. The Artisan's Quarter demands workshops with specialized tools. Each district has unique needs, but they all depend on the Guild to provide reliable, scalable infrastructure services.`,`The Guild used to provision everything manually through cloud consoles, a process that was slow, error-prone, and impossible to track. Recently, they've started adopting Infrastructure as Code, but the transition is incomplete.`,`The Guild Master has assigned you to complete the modernization journey.`,`Your mission: build the services and tools that will support CloudHaven's future growth.`],levels:[{id:`beginner`,name:`The Foundation Stones`,difficulty:`Beginner`,topics:[`OpenTofu`],learnings:[`Infrastructure as Code with OpenTofu`,`Remote state management with GCS backend`,`Dynamic resource provisioning with for_each`,`Conditional resources with the enabled meta-argument, new in OpenTofu`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F02-building-cloudhaven_01-beginner%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/practice-infrastructure-as-code-with-zero-setup-adventure-02-beginner/656`,deadline:`2026-02-04T23:59:00+01:00`,intro:[`An incomplete OpenTofu configuration is blocking the Merchant's Quarter from going live. Fix the broken backend, wire up dynamic resource provisioning with for_each, and use the new enabled meta-argument to conditionally deploy the audit database.`],backstory:[`The Merchant's Quarter needs essential services, but the previous Guild engineer left the OpenTofu configuration incomplete and misconfigured. The state is stored locally, making collaboration impossible, and some services remain half-configured or missing.`,`Your mission: fix the issues, complete the setup, and establish proper infrastructure management for the Guild.`],objective:[`Provision storage vaults and ledger databases for each district dynamically`,`Deploy the audit database only when there is more than one district`,`Store state remotely in a GCS backend following best practices so the Guild can collaborate`,`Resolve all TODOs in the code and successfully run tofu apply`],toolbox:[{name:`tofu`,description:`OpenTofu CLI for infrastructure provisioning`,url:`https://opentofu.org/`},{name:`gcp-api-mock`,description:`mock GCP API running locally to simulate cloud resources without real cloud costs (Cloud Storage and Cloud SQL only)`,url:`https://github.com/KatharinaSick/gcp-api-mock`}],howToPlay:[{title:`Wait for the Environment`,content:`<p>Wait ~2 minutes for the environment to initialize.</p>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 30104:</strong> GCP API Mock. Explore the mock cloud resources created by your configuration (Cloud Storage and Cloud SQL).</li>
</ul>`},{title:`Find the TODOs`,content:`<p>All OpenTofu files are in <code>adventures/02-building-cloudhaven/beginner/</code>. Run:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">grep -r "TODO" .
</code></pre>
<p>Files to review: <code>main.tf</code>, <code>state.tf</code>, <code>variables.tf</code>, <code>merchants.tf</code>, <code>audit.tf</code>, <code>outputs.tf</code>.</p>`},{title:`Apply the Configuration`,content:`<p>After fixing the TODOs, run:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">tofu apply
</code></pre>
<p>If you changed the backend configuration, run <code>tofu init -migrate-state</code> first.</p>`},{title:`Run the Smoke Test`,content:`<p>Run the smoke test to verify your solution:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">./smoke-test.sh
</code></pre>`}],helpfulLinks:[{title:`OpenTofu documentation`,url:`https://opentofu.org/docs/`},{title:`OpenTofu meta-arguments`,url:`https://opentofu.org/docs/language/meta-arguments/count/`},{title:`OpenTofu backend configuration`,url:`https://opentofu.org/docs/language/settings/backends/configuration/`},{title:`Google Cloud provider`,url:`https://registry.terraform.io/providers/hashicorp/google/latest/docs`}],verification:{command:`./smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`},metaDescription:`The Foundation Stones: An incomplete OpenTofu configuration is blocking the Merchant's Quarter from going live. Fix the broken backend, wire up dynamic...`},{id:`intermediate`,name:`The Modular Metropolis`,difficulty:`Intermediate`,topics:[`OpenTofu`,`TDD`],learnings:[`OpenTofu module testing with tofu test`,`Test-Driven Development (TDD) workflow`,`Input validation with custom rules`,`Refactoring infrastructure safely with moved blocks`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F02-building-cloudhaven_02-intermediate%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/adventure-02-building-cloudhaven-intermediate-the-modular-metropolis/723/10`,deadline:`2026-02-04T23:59:00+01:00`,intro:[`A senior engineer wrote the tests first and then left. The module code is buggy and the integration test is incomplete. Fix the implementation to match the test expectations, complete the end-to-end test, and use moved blocks to refactor without destroying state.`],backstory:[`After fixing the Foundation Stones, CloudHaven is thriving. The city has grown to three districts, and the Guild decided to refactor the infrastructure into reusable modules.`,`A senior engineer started the work using Test-Driven Development, writing tests first then implementing. But they were called away before finishing, leaving behind working tests and buggy code that doesn't match them.`,`Your mission: fix the bugs, complete the integration test, and deploy the infrastructure.`],objective:[`All tests of the districts module pass`,`A completed integration test that applies infrastructure against the mock GCP API to verify end-to-end functionality`,`Three districts deployed with correctly configured infrastructure (vaults and ledgers)`],toolbox:[{name:`tofu`,description:`OpenTofu CLI for infrastructure provisioning`,url:`https://opentofu.org/`},{name:`gcp-api-mock`,description:`mock GCP API running locally to simulate cloud resources without real cloud costs (Cloud Storage and Cloud SQL only)`,url:`https://github.com/KatharinaSick/gcp-api-mock`}],howToPlay:[{title:`Wait for the Environment`,content:`<p>Wait ~2 minutes for the environment to initialize.</p>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 30104:</strong> GCP API Mock. Explore mock cloud resources to verify your module configuration.</li>
</ul>`},{title:`Fix the Failing Tests`,content:`<p>All files are in <code>adventures/02-building-cloudhaven/intermediate/</code>. The tests define the expected behaviour: your job is to fix the implementation to match what the tests expect. Don't modify existing tests unless a comment tells you to.</p>
<pre tabindex="0" aria-label="Code block"><code>adventures/02-building-cloudhaven/intermediate/
├── main.tf                    # Provider and backend configuration
├── variables.tf               # Input variables
├── districts.tf               # Module calls for each district
├── outputs.tf                 # Infrastructure outputs
├── moved.tf                   # Resource migration blocks
├── modules/district/          # The district module (fix bugs here)
│   ├── main.tf                # Locals and tier configuration
│   ├── variables.tf           # Input validation
│   ├── vault.tf               # Storage bucket resource
│   ├── ledger.tf              # Cloud SQL resource
│   ├── outputs.tf             # Module outputs
│   └── tests/                 # Module tests (read these!)
└── tests/
    └── integration.tftest.hcl # Complete this test
</code></pre>
<p>Run tests to see what fails:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">make test
</code></pre>`},{title:`Apply the Infrastructure`,content:`<p>Once all tests pass, apply the infrastructure:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">make test
make apply
</code></pre>`},{title:`Run the Smoke Test`,content:`<p>Run the smoke test to verify your solution:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">./smoke-test.sh
</code></pre>`}],helpfulLinks:[{title:`OpenTofu testing`,url:`https://opentofu.org/docs/cli/commands/test/`},{title:`OpenTofu modules`,url:`https://opentofu.org/docs/language/modules/`},{title:`Input validation rules`,url:`https://opentofu.org/docs/language/values/variables/#custom-validation-rules`},{title:`Moved blocks`,url:`https://opentofu.org/docs/language/modules/develop/refactoring/`}],verification:{command:`./smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`},metaDescription:`The Modular Metropolis: A senior engineer wrote the tests first and then left. The module code is buggy and the integration test is incomplete. Fix the...`},{id:`expert`,name:`The Guardian Protocols`,difficulty:`Expert`,topics:[`OpenTofu`,`GitHub Actions`,`Trivy`],learnings:[`GitHub Actions for drift detection and plan/apply`,`Integration tests with service containers`,`Security scanning with Trivy`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F02-building-cloudhaven_03-expert%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/adventure-02-building-cloudhaven-expert-the-guardian-protocols/782/8`,deadline:`2026-02-04T23:59:00+01:00`,intro:[`Three broken GitHub Actions workflows stand between CloudHaven and automated infrastructure governance. Fix drift detection that creates PRs, PR validation with Trivy security scanning and service-container integration tests, and automatic apply on merge.`],backstory:[`After the Modular Metropolis refactoring, CloudHaven flourished. But with growth came risk. One night, a rogue change slipped through unnoticed and nearly brought down the North Market's trading vaults. The Council was furious: how could this happen without anyone noticing?`,`The Guild Master summoned you urgently. "We need guardians," she said. "Automated sentinels that watch over our infrastructure day and night. They must catch dangerous changes before they reach the city, detect when reality drifts from our blueprints, and sound the alarm when threats appear."`,`A previous engineer began building these Guardian Protocols using GitHub Actions, but was reassigned before completing them. The workflows exist, but they're incomplete and broken.`,`Your mission: bring the Guardian Protocols online and protect CloudHaven from chaos.`],objective:[`Drift detection: run tofu plan and create a PR when drift is found`,`PR validation: run tofu plan and comment results, run integration tests against the mock GCP API, scan for security vulnerabilities with Trivy and fail on critical or high severity issues`,`Automatic apply: apply infrastructure when a PR is merged to main`,`All three workflows must have succeeded at least once`],toolbox:[{name:`tofu`,description:`OpenTofu CLI for infrastructure provisioning`,url:`https://opentofu.org/`},{name:`gcp-api-mock`,description:`mock GCP API running locally (port set to public so GitHub Actions runners can access it)`,url:`https://github.com/KatharinaSick/gcp-api-mock`},{name:`GitHub Actions`,description:`the workflows you will fix are in .github/workflows/`,url:`https://docs.github.com/en/actions`}],howToPlay:[{title:`Wait for the Environment`,content:`<p>Wait ~2 minutes for the environment to initialize.</p>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 30104:</strong> GCP API Mock. Port is set to public so GitHub Actions runners can reach it during workflow runs. You may see a browser security warning. Click Continue to proceed.</li>
</ul>`},{title:`Fix the Workflows`,content:`<p>Fix the three workflows in <code>.github/workflows/</code>:</p>
<ul>
<li><code>adventure02-expert-detect-drift.yaml</code></li>
<li><code>adventure02-expert-validate-changes.yaml</code></li>
<li><code>adventure02-expert-apply-infrastructure.yaml</code></li>
</ul>
<p>The OpenTofu configuration is correct, focus only on the workflow files.</p>`},{title:`Trigger Drift Detection`,content:`<p>Commit and push to main. Go to the Actions tab, select the drift detection workflow, and click Run workflow. The infrastructure has intentional drift, so the workflow should create a draft PR.</p>`},{title:`Trigger Validation`,content:`<p>Click Ready for Review on the draft PR to trigger the validation workflow. To re-trigger validation after pushing new changes, convert the PR back to draft then Ready for Review again. Re-running a failed workflow uses the code from the original run, so toggling draft state is how you pick up new changes pushed to main.</p>`},{title:`Merge and Apply`,content:`<p>When the PR is merged to main, the apply workflow runs automatically.</p>`},{title:`Run the Smoke Test`,content:`<p>Run the smoke test to verify your solution:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">cd adventures/02-building-cloudhaven/expert
./smoke-test.sh
</code></pre>`}],helpfulLinks:[{title:`GitHub Actions documentation`,url:`https://docs.github.com/en/actions`},{title:`GitHub Actions service containers`,url:`https://docs.github.com/en/actions/use-cases-and-examples/using-containerized-services/about-service-containers`},{title:`OpenTofu plan command`,url:`https://opentofu.org/docs/cli/commands/plan/`},{title:`Trivy action`,url:`https://github.com/aquasecurity/trivy-action`},{title:`TF-via-PR action`,url:`https://github.com/OP5dev/TF-via-PR`}],verification:{command:`./smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`},metaDescription:`The Guardian Protocols: Three broken GitHub Actions workflows stand between CloudHaven and automated infrastructure governance. Fix drift detection that...`}]},{id:`echoes-lost-in-orbit`,title:`Echoes Lost in Orbit`,icon:`Satellite`,month:`DEC 2025`,story:`Restore interstellar communications by fixing broken GitOps setups, progressive delivery systems, and observability pipelines across three galactic missions.`,metaDescription:`Echoes Lost in Orbit: a hands-on Argo CD, Argo Rollouts, OpenTelemetry adventure on OffOn.`,tags:[`Argo CD`,`Argo Rollouts`,`OpenTelemetry`,`Jaeger`,`PromQL`],contributor:{name:`Katharina Sick`,url:`https://ksick.dev/`,aboutHtml:`DevRel at Dynatrace and co-organizer of Cloud Native Linz. Passionate about building user-friendly Cloud Native and Kubernetes solutions, with a background in mobile and backend development. Found in tech and sports communities, inline skating rinks, and quiz nights across Europe.`},backstory:[`Welcome aboard the GitOps Starliner, a multi-species engineering vessel orbiting the vibrant planet of Polaris-9. Life in this quadrant is wonderfully diverse, from the whispering cloud-dwellers of Nebulon to the rhythmic click-speakers of Crustacea Prime.`,`Communication between species used to be seamless, thanks to the Echo Server, a universal translator that instantly echoed your words in the listener's native format.`,`But lately, something's off. Messages are getting scrambled. Some transmissions never arrive. The Echo Server, deployed across the Staging Moonbase and the Production Outpost, is no longer syncing properly. The Argo CD dashboard shows no active deployments, and telemetry is suspiciously quiet.`,`You've been assigned to restore interstellar communication before the next critical mission.`],levels:[{id:`beginner`,name:`Broken Echoes`,difficulty:`Beginner`,topics:[`Argo CD`],learnings:[`Debug GitOps flows with Argo CD`,`ApplicationSet templating &#x26; pitfalls`,`Environment isolation &#x26; namespaces`,`Sync policies: automated, prune &#x26; self-heal`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F01-echoes-lost-in-orbit_beginner%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/adventure-01-echoes-lost-in-orbit-easy-broken-echoes/117/40`,deadline:`2025-12-10T09:00:00+01:00`,intro:[`The Echo Server is down across both environments. Investigate the Argo CD ApplicationSet configuration, spot the templating pitfalls, and restore proper multi-environment delivery.`],backstory:[`The Echo Server is misbehaving. Both environments seem to be down, and messages are silent.`,`Your mission: investigate the Argo CD configuration and restore proper multi-environment delivery.`],objective:[`See two distinct Applications in the Argo CD dashboard (one per environment)`,`Ensure each Application deploys to its own isolated namespace`,`Make the system resilient so Argo CD automatically reverts manual cluster changes`,`Confirm that updates roll out automatically without leaving stale resources behind`],toolbox:[{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`}],howToPlay:[{title:`Wait for Infrastructure`,content:`<p>Wait around 5 minutes for the Codespace to provision a Kubernetes cluster, Argo CD, and the sample app. Press Cmd+Shift+P (or Ctrl+Shift+P on Windows/Linux) and search for 'View Creation Log' to track progress.</p>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 30100:</strong> Argo CD (readonly / a-super-secure-password). View application sync status and manage Argo CD resources.</li>
</ul>`},{title:`Fix the ApplicationSet`,content:`<p>All errors are in this file:</p>
<pre tabindex="0" aria-label="Code block"><code>adventures/01-echoes-lost-in-orbit/beginner/manifests/appset.yaml
</code></pre>
<p>This challenge uses Kustomize under the hood: a base set of manifests with environment-specific overlays (staging, prod). Argo CD detects and applies these automatically, so your focus is on fixing the ApplicationSet to properly reference the Kustomize-managed paths.</p>
<p>After making changes, apply them:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">kubectl apply -n argocd -f adventures/01-echoes-lost-in-orbit/beginner/manifests/appset.yaml
</code></pre>`},{title:`Run the Smoke Test`,content:`<p>Run the smoke test to verify your solution locally:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">adventures/01-echoes-lost-in-orbit/beginner/smoke-test.sh
</code></pre>`}],verification:{command:`adventures/01-echoes-lost-in-orbit/beginner/smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`},metaDescription:`Broken Echoes: The Echo Server is down across both environments. Investigate the Argo CD ApplicationSet configuration, spot the templating pitfalls, and...`},{id:`intermediate`,name:`The Silent Canary`,difficulty:`Intermediate`,topics:[`Argo Rollouts`,`PromQL`],learnings:[`Progressive delivery with Argo Rollouts`,`Canary deployments &#x26; automated analysis`,`Write PromQL queries for health validation`,`Kube-state-metrics for deployment decisions`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F01-echoes-lost-in-orbit_intermediate%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/adventure-01-echoes-lost-in-orbit-intermediate-the-silent-canary/310/8`,deadline:`2025-12-24T09:00:00+01:00`,intro:[`A canary rollout is stuck and the Zephyrians are still waiting to communicate. Debug the broken progressive delivery system by writing PromQL health checks that let Argo Rollouts automatically validate and advance the deployment.`],backstory:[`After fixing the communication outage in Level 1, the Intergalactic Union welcomed a new species: the Zephyrians.`,`The communications team attempted to deploy their language files using a progressive delivery system, but the rollout is failing. The Zephyrians are still waiting to communicate with the rest of the galaxy.`,`A previous engineer configured automated canary deployments with health checks but left the setup incomplete.`,`Your mission: debug the broken rollout and bring the Zephyrians' voices online.`],objective:[`Pod info version 6.9.3 deployed successfully in both staging and production environments`,`Rollouts automatically progress through canary stages based on health metrics`,`Two working PromQL queries in the AnalysisTemplate that validate application health during releases`,`All rollouts complete successfully`],toolbox:[{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`},{name:`Argo CD CLI`,description:`manage Argo CD applications from the command line`,url:`https://argo-cd.readthedocs.io/en/latest/user-guide/commands/argocd/`},{name:`Argo Rollouts kubectl plugin`,description:`extended kubectl commands for managing rollouts`,url:`https://argo-rollouts.readthedocs.io/en/stable/features/kubectl-plugin/`}],howToPlay:[{title:`Wait for Infrastructure`,content:`<p>Wait ~5-10 minutes for infrastructure to deploy. After it deploys, the setup script starts port forwarding to the Argo Rollouts dashboard, keeping a terminal busy. Open a new terminal to run commands.</p>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 30100:</strong> Argo CD (readonly / a-super-secure-password). Shows sync status. Use to refresh applications after pushing commits.</li>
<li><strong>Port 30101:</strong> Argo Rollouts. Shows canary deployment progress and analysis status.</li>
<li><strong>Port 30102:</strong> Prometheus. Explore available metrics and test PromQL queries. CLI tools work equally well if you prefer the terminal.</li>
</ul>`},{title:`Fix the Manifests`,content:`<p>Review and fix the configuration in <code>adventures/01-echoes-lost-in-orbit/intermediate/manifests/</code>.</p>
<p>This challenge uses Kustomize under the hood: a base set of manifests with environment-specific overlays (staging, prod). Argo CD detects and applies these automatically, so you don't need to run Kustomize commands manually.</p>`},{title:`Deploy Your Changes`,content:`<p>Commit and push your changes to trigger the deployment:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">git add adventures/01-echoes-lost-in-orbit/intermediate/manifests/
git commit -m "Fix configuration"
git push
</code></pre>
<p>If pushing to a branch other than main, also update the ApplicationSet in <code>appset.yaml</code> to point to your branch.</p>
<p>Speed up Argo CD sync:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">argocd app get echo-server-staging --refresh
argocd app get echo-server-prod --refresh
</code></pre>`},{title:`Trigger the Rollout`,content:`<p>After Argo CD syncs, retry the rollouts:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">kubectl argo rollouts retry rollout echo-server -n echo-staging
kubectl argo rollouts retry rollout echo-server -n echo-prod
</code></pre>`},{title:`Watch the Rollout`,content:`<p>Watch canary progress (should advance 33% to 66% to 100%):</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">kubectl argo rollouts get rollout echo-server -n echo-staging --watch
kubectl argo rollouts get rollout echo-server -n echo-prod --watch
</code></pre>
<p>In real-world progressive delivery, staging is updated first, validated, and then changes are promoted to production. This challenge skips that separation so you can focus on the canary rollout mechanics and health checks without managing two promotion steps.</p>`},{title:`Run the Smoke Test`,content:`<p>Run the smoke test to verify your solution:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">adventures/01-echoes-lost-in-orbit/intermediate/smoke-test.sh
</code></pre>`}],helpfulLinks:[{title:`Argo Rollouts documentation`,url:`https://argo-rollouts.readthedocs.io/en/stable/`},{title:`Analysis and progressive delivery`,url:`https://argo-rollouts.readthedocs.io/en/stable/features/analysis/`},{title:`PromQL basics`,url:`https://prometheus.io/docs/prometheus/latest/querying/basics/`},{title:`kube-state-metrics exposed metrics`,url:`https://github.com/kubernetes/kube-state-metrics/tree/main/docs#exposed-metrics`}],verification:{command:`adventures/01-echoes-lost-in-orbit/intermediate/smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`},metaDescription:`The Silent Canary: A canary rollout is stuck and the Zephyrians are still waiting to communicate. Debug the broken progressive delivery system by writing...`},{id:`expert`,name:`Hyperspace Operations & Transport`,difficulty:`Expert`,topics:[`Argo Rollouts`,`OpenTelemetry`,`Jaeger`,`PromQL`],learnings:[`Configure OpenTelemetry Collector pipelines`,`Spanmetrics connector (traces to metrics)`,`Detect idle canaries with traffic validation`,`Distributed tracing with Jaeger`],codespacesUrl:`${n}?devcontainer_path=.devcontainer%2F01-echoes-lost-in-orbit_expert%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${r}/t/adventure-01-echoes-lost-in-orbit-expert-hyperspace-operations-transport/351/4`,deadline:`2026-01-14T09:00:00+01:00`,intro:[`The observability pipeline is broken and HotROD's canary can't validate. Wire an OpenTelemetry Collector with spanmetrics to convert distributed traces into Prometheus metrics, then write PromQL queries that catch idle canaries, high error rates, and latency spikes.`],backstory:[`After fixing the Zephyrian communications, word of your progressive release mastery spread across the galaxy. The Bytari, a highly advanced species from the Andromeda sector, were impressed.`,`They want to apply progressive delivery to their mission-critical service: HotROD (Hyperspace Operations &#x26; Transport, Rapid Orbital Dispatch), an interstellar ride-sharing service handling dispatch requests across thousands of star systems. Every millisecond of latency matters, and any error could strand travelers between dimensions.`,`A previous engineer started instrumenting HotROD with OpenTelemetry and configured Argo Rollouts for automated validation, but left the setup incomplete. The observability pipeline is broken. The Bytari don't use staging/production environments; they believe in single-environment progressive delivery validated purely by trace-derived metrics and automated health checks.`,`Your mission: fix the observability pipeline and canary validation. Make HotROD deployment-ready with proper distributed tracing.`],objective:[`Automated rollout progression to HotROD version 1.76.0 driven by observability signals`,`OpenTelemetry Collector configured with an OTLP receiver for HotROD traces, a Spanmetrics connector converting traces to metrics, trace export to Jaeger, and metrics export to Prometheus`,`Canary analysis with three PromQL queries: traffic detection (at least 0.05 req/s to prevent idle canaries), error rate below 5%, and 95th-percentile latency below 1000ms`],toolbox:[{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`},{name:`Argo CD CLI`,description:`manage Argo CD applications from the command line`,url:`https://argo-cd.readthedocs.io/en/latest/user-guide/commands/argocd/`},{name:`Argo Rollouts kubectl plugin`,description:`extended kubectl commands for managing rollouts`,url:`https://argo-rollouts.readthedocs.io/en/stable/features/kubectl-plugin/`}],howToPlay:[{title:`Wait for Infrastructure`,content:`<p>Wait ~5-10 minutes for infrastructure to deploy. Port forwarding starts automatically after infrastructure is ready, keeping a terminal busy. Open a new terminal to run commands.</p>`},{title:`Explore the UIs`,content:`<p>Open the <strong>Ports</strong> tab and navigate to each service:</p>
<ul>
<li><strong>Port 30100:</strong> Argo CD (readonly / a-super-secure-password). Shows sync status. Use to refresh applications after pushing commits.</li>
<li><strong>Port 30101:</strong> Argo Rollouts. Shows canary deployment progress and analysis status.</li>
<li><strong>Port 30102:</strong> Prometheus. Explore available metrics and test PromQL queries. CLI tools work equally well if you prefer the terminal.</li>
<li><strong>Port 30103:</strong> Jaeger. Shows distributed traces from HotROD to verify that tracing is working end-to-end.</li>
</ul>`},{title:`Fix the Manifests`,content:`<p>Fix the manifests in <code>adventures/01-echoes-lost-in-orbit/expert/manifests/</code>. Use the Argo Rollouts dashboard, Prometheus UI, and Jaeger UI to debug and validate your changes.</p>`},{title:`Deploy Your Changes`,content:`<p>Commit and push to trigger the deployment:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">git add adventures/01-echoes-lost-in-orbit/expert/manifests/
git commit -m "Fix configuration"
git push
</code></pre>
<p>If pushing to a branch other than main, also update the ApplicationSet in <code>appset.yaml</code> to point to your branch.</p>
<p>Refresh Argo CD apps:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">argocd app get hotrod --refresh
argocd app get otel --refresh
</code></pre>
<p>If you changed HotROD, retry the rollout:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">kubectl argo rollouts retry rollout hotrod -n hotrod
</code></pre>
<p>If you changed the OTel Collector config, restart it:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">kubectl rollout restart daemonset/collector -n otel
</code></pre>`},{title:`Watch the Rollout`,content:`<p>Watch rollout progress. The rollout should progress automatically based on analysis metrics:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">kubectl argo rollouts get rollout hotrod -n hotrod --watch
</code></pre>`},{title:`Run the Smoke Test`,content:`<p>Run the smoke test to verify your solution:</p>
<pre tabindex="0" aria-label="Code block"><code class="language-sh">adventures/01-echoes-lost-in-orbit/expert/smoke-test.sh
</code></pre>`}],helpfulLinks:[{title:`OpenTelemetry Collector configuration`,url:`https://opentelemetry.io/docs/collector/configuration/`},{title:`Span Metrics Connector`,url:`https://github.com/open-telemetry/opentelemetry-collector-contrib/tree/main/connector/spanmetricsconnector`},{title:`Argo Rollouts analysis`,url:`https://argo-rollouts.readthedocs.io/en/stable/features/analysis/`},{title:`PromQL basics`,url:`https://prometheus.io/docs/prometheus/latest/querying/basics/`}],verification:{command:`adventures/01-echoes-lost-in-orbit/expert/smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`},metaDescription:`Hyperspace Operations & Transport: The observability pipeline is broken and HotROD's canary can't validate. Wire an OpenTelemetry Collector with spanmetrics...`}]}];Array.from(new Set(o.flatMap(e=>e.tags))).sort(),Object.values(o.filter(e=>e.contributor!==void 0).reduce((e,t)=>{let n=t.contributor.name;return e[n]||(e[n]={name:t.contributor.name,url:t.contributor.url,aboutHtml:t.contributor.aboutHtml,adventures:[]}),e[n].adventures.push({id:t.id,title:t.title}),e},{}));var s=e(),c=({items:e,className:n=`mb-5`})=>(0,s.jsx)(`nav`,{"aria-label":`Breadcrumb`,className:n,children:(0,s.jsx)(`ol`,{className:`flex flex-wrap items-center gap-1 text-xs text-[hsl(var(--text-faint))]`,children:e.map((e,n)=>(0,s.jsxs)(`li`,{className:`flex items-center gap-1`,children:[n>0&&(0,s.jsx)(a,{size:12,"aria-hidden":`true`,className:`shrink-0`}),e.href?(0,s.jsx)(t,{to:e.href,className:`inline-flex min-h-6 items-center hover:text-foreground transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring rounded-sm`,children:e.label}):(0,s.jsx)(`span`,{"aria-current":`page`,children:e.label})]},e.label))})});export{o as n,c as t};